insert into public.knowledge_entries
  (type, title, body, category, tags, source_type, source_id, source_title, status, confidence, created_by)
values
('term','보험 의료자문 공정성 문제','보험사가 보험금 지급 심사 과정에서 보험사 측 자문의 소견을 이유로 주치의 진단을 번복하거나 보험금을 거절·감액하는 관행. 중립성·공정성 논란이 지속되어 금감원-의협 간 업무협약(MOU)을 통한 제3의료자문 절차가 도입됨. 보험계약자는 보험사 자문의 의견만으로 지급 거부 시 이의 제기 및 분쟁조정 가능. 시범사업은 심·뇌혈관 질환, 후유장애 진단 관련 의료자문으로 대상을 한정하여 6개월 운영 후 확대 여부를 점검하는 방식으로 운영 중.','민원',array['의료자문','자문의','보험금 거부','의협 MOU','분쟁민원'],'cycle2_supp','cycle2_supp','의협신문 doctorsnews.co.kr ''공정성 논란 보험사 셀프 자문 차단'' / 금감원-의협 업무협약 관련 보도 bosa.co.kr 2024','ai_draft','medium','admin'),
('term','사망보험금 간주상속재산 과세(상속세 및 증여세법 제8조)','피상속인이 보험계약자이거나 실질적으로 보험료를 납부한 경우, 그 사망으로 지급받는 생명·손해보험 사망보험금은 상속세 및 증여세법 제8조에 따라 상속재산으로 간주하여 상속세 과세. 보험금 중 상속세 과세 금액: 수령 보험금 × (피상속인 납부 보험료 / 총 납부 보험료 합계). 수익자가 법정상속인인 경우 상속 고유재산이나 계약자가 피상속인이면 간주상속재산으로 과세됨.','세제',array['사망보험금 상속세','간주상속재산','상속세 및 증여세법 제8조','보험금 과세'],'cycle2_supp','cycle2_supp','상속세 및 증여세법 제8조(국가법령정보센터 law.go.kr) / TAXLY ''상속재산으로 보는 보험금(간주상속재산)'' taxly.kr','ai_draft','high','admin'),
('term','보험수익자 사망 후 보험금 귀속(상법 제733조)','지정 보험수익자가 피보험자보다 먼저 사망하고 계약자가 수익자를 재지정하지 않으면, 상법 제733조 제3항·제4항에 따라 사망한 수익자의 상속인이 수익자가 됨. 대법원 2025.2.20. 선고 2022다306048 중요판결: 지정 수익자 사망 후 재지정 없이 보험사고 발생 시, 수익자 상속인이 생존하지 않은 경우 순차 상속인 중 보험사고 발생 당시 생존한 자가 수익자가 됨. 보험수익자가 여럿인 경우 법정상속분 비율로 보험금청구권 취득. 수익자 미지정 시 피보험자(사망자)의 법정상속인이 수익자(상속인의 고유재산으로 상속채무와 분리).','계약',array['보험수익자 사망','수익자 재지정','상법 제733조','보험금 귀속','법정상속인'],'cycle2_supp','cycle2_supp','대법원 2025.2.20. 선고 2022다306048 판결(scourt.go.kr 판례속보 seqnum=10298) / 국가법령정보센터 law.go.kr 판례 precSeq=604041','ai_draft','high','admin'),
('term','보험계약대출(약관대출) 원리금 초과 시 계약 해지','보험계약대출(약관대출) 원리금이 해약환급금을 초과하면 보험사가 보험계약을 자동 해지(상계 처리)할 수 있음. 미납 이자는 별도 연체이자 없이 원금에 가산되며 복리로 불어남. 계약 해지 시 신용정보원에 연체 기록은 남지 않음. 설계사의 해지 위험 안내 의무가 실무적 민원 포인트. 자동대출납입 특약과 혼동 주의.','계약',array['약관대출','보험계약대출','원리금 초과 해지','해약환급금','복리 이자'],'cycle2_supp','cycle2_supp','금감원 소비자 주의보 insjournal.co.kr ''보험 약관대출 미상환 땐 연금 못 받을 수도'' / 뱅크샐러드 ''보험계약대출 이자 한도'' banksalad.com','ai_draft','high','admin'),
('term','휴면보험금 조회 및 청구 — 내보험 찾아줌','소멸시효(3년)가 완성된 보험금은 보험회사가 서민금융진흥원에 출연하기 전까지 ''휴면보험금''으로 보관됨. 금감원 파인(fine.fss.or.kr) 및 생명·손해보험협회 공동 운영 ''내보험찾아줌(cont.insure.or.kr)''에서 365일 24시간 통합 조회·간편 청구 가능. 정부24, 어카운트인포, 카카오뱅크 등 다양한 채널로도 신청 가능. 소멸시효 완성 후에도 채권은 존재하므로 청구 시 지급 가능.','민원',array['휴면보험금','내보험찾아줌','숨은 보험금','금감원 파인','보험금 조회'],'cycle2_supp','cycle2_supp','금감원 파인 fine.fss.or.kr ''내보험 찾아줌'' / 생명·손해보험협회 공동 운영 cont.insure.or.kr / 정부24 gov.kr ''휴면예금과 휴면보험금의 조회 및 지급신청''','ai_draft','high','admin'),
('term','한국표준질병사인분류(KCD) 외인 코드와 재해보험','보험약관의 재해분류표는 한국표준질병사인분류(KCD) V·W·X·Y 코드 범주(외인: 손상·중독·기타)와 연계됨. 재해사망·재해장해 보험금 청구 시 사망진단서 또는 장해진단서의 KCD 코드가 재해분류표 범위 내인지 여부로 지급 여부 결정. 질병 코드(A~N)와 외인 코드(V~Y)의 구분이 보험금 지급 분쟁의 핵심. 질병분류정보센터(koicd.kr)에서 코드 조회 가능.','보장',array['KCD 코드','외인 코드','재해분류표','재해사망 판단','한국표준질병사인분류'],'cycle2_supp','cycle2_supp','질병분류정보센터 KOICD koicd.kr / 찾기쉬운 생활법령 ''보험의 종류에 따른 보험금 지급사유 및 면책사유 예시'' easylaw.go.kr csmSeq=526','ai_draft','high','admin'),
('term','장해보험금 장해판정시기 및 청구 시점','장해보험금은 장해가 ''확정''된 시점에 청구 가능. 일반적으로 사고·진단확정일로부터 180일(6개월) 경과 후 판정하나, 의사 판단으로 영구장해가 명확히 확정된 경우 180일 전에도 청구 가능. 180일 이내에 장해지급률이 확정되지 않으면 180일이 되는 날의 의사 진단에 기초하여 고정될 것으로 인정되는 상태를 기준으로 결정. 청구권 소멸시효는 3년이며, 기왕 사고의 후유장해도 장해 진단일로부터 3년 이내 청구 가능.','보장',array['장해보험금 청구시점','장해판정시기','180일','영구장해','후유장해 소멸시효'],'cycle2_supp','cycle2_supp','하나생명 청구사유별 안내 장해보험금 hanalife.co.kr / 보험연구원(KIRI) ''보험금청구권과 소멸시효'' kiri.or.kr','ai_draft','medium','admin'),
('term','지정대리청구인 임의대리인 구분','지정대리청구인: 치매·중대질병·중대상해 등으로 본인 청구 불가 시를 대비해 계약 시 또는 보험기간 중 사전 지정(배우자 또는 3촌 이내 친족, 동거 또는 생계 동일). 특약 가입 필요. 임의대리인: 수익자의 위임장·인감증명서 첨부로 일시적 대리 청구 가능, 사전 지정 불필요. 지정대리청구인은 보험사가 본인 확인 없이 처리 가능한 반면 임의대리인은 서류 심사 강화. 생명보험 표준약관에 별도 특약으로 규정.','계약',array['지정대리청구인','임의대리인','보험금 대리청구','치매 대리청구','보험금 청구 대리'],'cycle2_supp','cycle2_supp','금융감독원 표준약관(fss.or.kr 금융소비자보호 표준약관 목록) / 보험업감독업무시행세칙 별표15(국가법령정보센터 law.go.kr) / 찾기쉬운 생활법령 보험금 지급(easylaw.go.kr)','ai_draft','medium','admin'),
('term','인보험 대위 금지(상법 제729조) 및 상해보험 예외','상법 제729조: 생명보험 등 인보험에서 보험자는 피보험자·수익자의 제3자에 대한 권리를 대위 행사할 수 없음(인보험 대위 금지 원칙). 이는 피보험자 보호와 이중이득 허용 의도에 근거. 단, 상해보험에서 당사자 간 약정이 있으면 피보험자의 권리를 해하지 않는 범위에서 예외적 대위 가능(동조 단서). 결과적으로 같은 사고에서 제3자 손해배상금과 보험금을 동시 수령 가능(인보험 이중이득 허용).','계약',array['인보험 대위 금지','상법 제729조','상해보험 예외 대위','이중이득 허용'],'cycle2_supp','cycle2_supp','상법 제729조(국가법령정보센터 law.go.kr / LBOX lbox.kr) / 대법원 2014. 10. 15. 선고 2012다88716 판결(casenote.kr) / 찾기쉬운 생활법령 인보험(easylaw.go.kr)','ai_draft','high','admin'),
('term','약관 설명의무 위반과 편입통제(약관 배제 효과)','보험자가 보험약관의 명시·설명의무를 위반하여 계약을 체결한 경우, 그 약관 내용을 보험계약의 내용으로 주장할 수 없다(약관규제법 제3조 제4항). 상법 제638조의3과 약관규제법 제3조는 동일한 설명의무를 부과하고, 위반 효과로 전자는 1개월 이내 취소권, 후자는 약관의 계약 편입 배제를 각각 정한다. 판례는 양법적용설을 취하여 두 효과가 중첩적으로 적용됨을 인정한다(대법원 96다4893 등). 단, 거래상 일반적이고 공통된 사항, 이미 법령에 정하여진 것을 되풀이하는 정도의 사항에는 설명의무가 인정되지 않는다.','계약',array['약관편입통제','설명의무위반','약관배제','상법638조의3','약관규제법제3조','편입통제'],'cycle2_supp','cycle2_supp','약관의 규제에 관한 법률 제3조(casenote.kr) / 상법 제638조의3(casenote.kr) / 대법원 1996. 4. 12. 선고 96다4893 판결(casenote.kr) / 보험약관 설명의무에 대한 연구(보험연구원 연구보고서 2023-19)','ai_draft','medium','admin'),
('term','작성자 불이익 원칙(보험약관 해석)','보험약관 해석은 평균적 고객의 이해가능성을 기준으로 객관적·획일적으로 하여야 하며, 이 방법으로도 약관 조항이 다의적으로 해석되고 각 해석이 합리성이 있는 경우에 한하여 보충적으로 고객에게 유리하게 해석(작성자 불이익 원칙)을 적용한다. 하나의 합리적 해석만 가능하다면 그것이 고객에게 불리하더라도 동 원칙은 적용되지 않는다(보충적 해석원칙). 대법원 2018다203395, 2017다256828 판결이 주요 선례. 법적 근거는 약관규제법 제5조 제2항.','계약',array['작성자불이익원칙','약관해석','다의적해석','보충적해석','평균적고객기준','약관규제법5조'],'cycle2_supp','cycle2_supp','약관의 규제에 관한 법률 제5조(casenote.kr / LBOX lbox.kr) / 대법원 2018. 6. 28. 선고 2018다203395 판결(casenote.kr) / 대법원 2018. 7. 24. 선고 2017다256828 판결(LBOX lbox.kr) / 보험연구원 연구보고서 2022-07','ai_draft','high','admin'),
('term','개별약정 우선 원칙(보험계약)','약관규제법 제4조는 약관에서 정하는 사항에 관하여 사업자와 고객이 약관 내용과 다르게 합의한 경우 그 합의(개별약정)가 약관보다 우선하여 계약 내용이 됨을 규정한다. 보험계약에서도 보험자와 계약자가 표준약관과 다르게 개별 합의한 내용은 약관에 우선 적용된다. 다만 상법 제663조(불이익변경금지 원칙)와의 관계상, 개별약정이라도 보험계약자에게 불리한 방향으로 상법 강행규정을 배제할 수는 없다.','계약',array['개별약정우선','약관규제법4조','개별합의','약관우선순위','불이익변경금지'],'cycle2_supp','cycle2_supp','약관의 규제에 관한 법률 제4조(국가법령정보센터 law.go.kr / casenote.kr) / 보험연구원 연구보고서 2023-19','ai_draft','high','admin'),
('term','불이익변경금지 원칙(상법 제663조)','상법 제663조는 보험편의 규정을 당사자 간 특약으로 보험계약자·피보험자·보험수익자의 불이익으로 변경하지 못한다고 규정하는 상대적 강행규정이다. 다만 재보험 및 해상보험 기타 이와 유사한 보험의 경우에는 이 원칙이 적용되지 않는다(동조 단서). 따라서 약관이 상법 보험편 규정보다 보험계약자에게 불리한 내용을 정하면 당해 약관 조항은 무효가 된다. 보험계약자에게 유리한 방향의 변경(상법보다 넓은 보장 등)은 허용된다.','계약',array['불이익변경금지','상법663조','강행규정','약관무효','보험계약자보호'],'cycle2_supp','cycle2_supp','상법 제663조(국가법령정보센터 law.go.kr / LBOX lbox.kr) / 대법원 1996. 12. 20. 선고 96다23818 판결(casenote.kr)','ai_draft','medium','admin'),
('term','보험계약 부활 시 고지의무 재발생','실효된 보험계약이 부활될 때 부활계약은 신계약에 준하는 성격을 가지므로 보험계약자·피보험자에게 고지의무가 재발생한다. 부활청약 시점의 건강상태·직업 등 중요한 사항을 보험자에게 다시 고지해야 하며, 이를 위반하면 보험자는 상법 제651조에 따라 계약을 해지할 수 있다. 부활 이후 고지의무 위반을 이유로 한 해지권 제척기간(안날로부터 1월, 부활일로부터 3년)도 부활일을 기산점으로 새로 진행된다.','계약',array['부활시고지의무','부활계약고지','실효부활고지','상법650조의2','고지의무재발생'],'cycle2_supp','cycle2_supp','상법 제650조의2 준용규정(casenote.kr / law.go.kr) / 상법 제651조(casenote.kr) / 찾기쉬운 생활법령 보험계약 부활(easylaw.go.kr)','ai_draft','high','admin'),
('term','타인을 위한 보험(상법 제639조) — 계약 구조와 권리 귀속','보험계약자는 위임 유무와 무관하게 특정 또는 불특정의 타인을 위하여 보험계약을 체결할 수 있다(상법 제639조). 손해보험에서는 피보험자, 생명보험에서는 보험수익자가 ''타인''에 해당하며, 타인은 별도 의사표시 없이 당연히 계약의 이익을 받는다. 보험계약자는 원칙적으로 보험금청구권을 갖지 않으며, 보험계약자가 파산하거나 보험료 지급을 지체한 경우 타인도 보험료 납입의무를 부담할 수 있다.','계약',array['타인을위한보험','상법639조','피보험자권리귀속','보험계약자피보험자분리','타인보험이익'],'cycle2_supp','cycle2_supp','상법 제639조(국가법령정보센터 law.go.kr / casenote.kr) / 찾기쉬운 생활법령 타인의 동의 없는 보험(easylaw.go.kr)','ai_draft','high','admin'),
('term','타인의 생명보험과 피보험자 서면동의(상법 제731조)','타인의 사망을 보험사고로 하는 생명보험계약은 계약 체결 시까지 피보험자의 서면 동의를 반드시 받아야 한다(상법 제731조 제1항). 동의는 각 계약별 개별적 서면동의여야 하며 포괄·묵시·추정 동의로는 부족하다. 이 규정은 강행규정으로, 서면동의 없이 체결된 계약은 확정적 무효이며 사후 추인으로도 유효화될 수 없다(대법원 2004다56677). 도박보험 방지·피보험자 살해 위험 방지를 목적으로 한다.','계약',array['타인의생명보험','상법731조','피보험자서면동의','강행규정무효','사망보험동의'],'cycle2_supp','cycle2_supp','상법 제731조(국가법령정보센터 law.go.kr) / 대법원 2006. 9. 22. 선고 2004다56677 판결(casenote.kr / law.go.kr) / 찾기쉬운 생활법령 보험계약 무효(easylaw.go.kr)','ai_draft','high','admin'),
('term','보험수익자 지정·변경권(상법 제733조·제734조)','보험계약자는 보험수익자를 지정·변경할 권리를 가진다(상법 제733조). 이 변경권은 형성권으로서 보험자나 보험수익자의 동의 없이 자유롭게 행사할 수 있으며, 변경의 의사표시가 객관적으로 확인되는 즉시 효력이 발생한다(보험자 도달 불요). 다만 보험자에게 변경 통지를 하지 않으면 보험자에게 대항하지 못한다(상법 제734조). 보험계약자가 변경권을 행사하지 않고 사망하면 보험수익자의 권리가 확정되고, 보험계약자가 지정권을 행사하지 않고 사망하면 피보험자가 보험수익자가 된다.','계약',array['보험수익자변경권','상법733조','상법734조','형성권','수익자지정변경통지'],'cycle2_supp','cycle2_supp','상법 제733조·제734조(국가법령정보센터 law.go.kr / LBOX lbox.kr) / 대법원 2018. 7. 12. 선고 2017다235647 판결(casenote.kr) / 찾기쉬운 생활법령(easylaw.go.kr)','ai_draft','high','admin'),
('term','단체보험(상법 제735조의3) — 규약과 피보험자 동의 예외','단체가 규약에 따라 구성원의 전부 또는 일부를 피보험자로 하는 생명보험계약을 체결하는 경우 피보험자 개별 서면동의(상법 제731조)의 적용이 배제된다(상법 제735조의3 제1항). 단, 규약은 단체협약·취업규칙·정관 등 형식을 불문하고 대표자가 구성원을 위해 일괄 계약을 체결할 수 있다는 취지가 담겨 있어야 한다. 규약 없이 단체보험 형식으로 체결한 계약은 피보험자 개별 서면동의 없이는 무효이다. 보험계약자가 피보험자 외의 자를 수익자로 지정할 때에는 규약에 명시적 정함이 없는 한 피보험자 서면동의 필요.','계약',array['단체보험','상법735조의3','규약동의대체','피보험자동의예외','단체협약취업규칙'],'cycle2_supp','cycle2_supp','상법 제735조의3(국가법령정보센터 law.go.kr); 대법원 2020. 2. 6. 선고 2017다215728 판결(국가법령정보센터 precSeq=210793)','ai_draft','high','admin'),
('term','단체보험 보험금청구권 귀속(대법원 2017다215728)','단체보험계약에서 피보험자의 상속인이 보험수익자로 지정된 경우, 피보험자 사망 시 보험금청구권은 상속인의 고유재산으로 취득하는 것이며 상속재산이 아니다. 따라서 상속인 중 한 명이 보험금청구권을 포기하더라도 포기 부분이 다른 상속인에게 귀속되지 않는다(대법원 2020. 2. 6. 선고 2017다215728). 이는 생명보험 수익자 지정의 법적 성격이 수익자의 고유한 권리임을 확인한 판결이다.','계약',array['단체보험보험금귀속','상속재산제외','고유재산취득','대법원2017다215728','수익자포기'],'cycle2_supp','cycle2_supp','대법원 2020. 2. 6. 선고 2017다215728 판결(국가법령정보센터 precSeq=210793; CaseNote)','ai_draft','high','admin'),
('term','고지의무 해지권 제척기간(상법 제651조) — 1월/3년','보험자의 고지의무 위반으로 인한 계약 해지권은 두 가지 제척기간의 제한을 받는다. 첫째, 위반 사실을 안 날로부터 1개월 이내(상대적 제척기간), 둘째, 계약 체결일로부터 3년 이내(절대적 제척기간). 이 기간이 경과하면 고지의무 위반이 있더라도 해지권이 소멸하여 보험사고 발생 시 보험금을 지급해야 한다. 단, 보험자가 계약 당시 위반 사실을 알았거나 중대한 과실로 몰랐을 경우 해지권이 인정되지 않는다. 2011년 개정 이전에는 절대적 기간이 5년이었으나 현행은 3년이다.','계약',array['고지의무해지권제척기간','상법651조','1개월제척','3년제척','해지권소멸'],'cycle2_supp','cycle2_supp','상법 제651조(국가법령정보센터 law.go.kr); CaseNote 상법 제651조 해설','ai_draft','high','admin'),
('term','고지방해와 고지의무 위반 해지권 제한(보험업법 제97조 제1항 제4호)','보험모집종사자가 보험계약자·피보험자로 하여금 중요 사항을 고지하지 않도록 유도하거나 부실 고지를 방해한 경우, 보험자는 그 고지의무 위반을 이유로 보험계약을 해지할 수 없다(보험업법 제97조 제1항 제4호 위반 + 관련 판례). 설계사의 ''괜찮다''는 유도나 청약서 허위 기재 방조가 이에 해당하며, 이를 주장하려면 보험계약자가 방해 행위를 입증해야 한다. 상법 제651조의2는 ''보험자가 서면으로 질문한 사항은 중요한 사항으로 추정한다''는 규정으로서 고지방해와 직접 관련 없는 별도 조문이다.','계약',array['고지방해','보험업법97조제1항제4호','설계사고지유도','해지권제한','고지의무위반'],'cycle2_supp','cycle2_supp','보험업법 제97조 제1항 제4호(국가법령정보센터 law.go.kr); 상법 제651조의2(국가법령정보센터)','ai_draft','medium','admin'),
('term','고지의무 위반과 보험사고 인과관계(상법 제655조 단서)','보험사고 발생 후 고지의무 위반을 이유로 보험계약을 해지한 경우에도, 고지의무 위반 사실이 보험사고 발생에 영향을 미치지 않았음이 증명되면 보험자는 보험금 지급 책임을 면하지 못한다(상법 제655조 단서). 인과관계 부존재의 입증책임은 보험계약자·피보험자가 부담한다는 것이 대법원 확립 법리(대법원 92다28259 등)이다. 인과관계 없는 보험사고는 해지 후에도 보험금의 전부에 대한 지급 책임이 있다.','계약',array['고지의무위반인과관계','상법655조단서','인과관계없으면보험금지급','해지후보험금','입증책임'],'cycle2_supp','cycle2_supp','상법 제655조(국가법령정보센터 law.go.kr); 대법원 1992. 10. 23. 선고 92다28259 판결(CaseNote); 국가법령정보센터 precSeq=600295(인과관계 판단 사건)','ai_draft','medium','admin'),
('term','보험계약 사고 전 선의 무효(상법 제644조)','보험계약 체결 당시 보험사고가 이미 발생하였거나 발생 가능성이 없는 경우 그 계약은 원칙적으로 무효이다(상법 제644조). 단, 당사자 쌍방과 피보험자 모두가 이를 알지 못한 경우(선의)에는 예외적으로 계약이 유효하다. 관련 당사자 중 한 명이라도 사고 확정 사실을 알았으면 선의 예외가 적용되지 않아 계약은 무효가 된다(대법원 97다50091, 2010다66835).','계약',array['보험사고확정무효','상법644조','선의예외','보험계약무효요건','사고발생불능'],'cycle2_supp','cycle2_supp','상법 제644조(국가법령정보센터 law.go.kr); 대법원 1998. 8. 21. 선고 97다50091 판결(CaseNote); 대법원 2010. 12. 9. 선고 2010다66835 판결(CaseNote)','ai_draft','high','admin'),
('term','보험계약 통지의무(상법 제652조) — 위험변경증가 판단기준','보험기간 중 보험계약자·피보험자가 사고 발생 위험이 현저하게 변경 또는 증가된 사실을 알게 된 경우 지체 없이 보험자에게 통지해야 한다(상법 제652조). 고지의무(계약 체결 시)와 달리 통지의무는 계약 성립 이후 새로운 위험 변화에 대한 의무이다. 하나의 보험회사에 여러 보험계약이 있는 경우 통지의무 이행 여부는 통지의 내용·경위·보험사 처리 경과를 종합하여 판단한다(대법원 2024. 11. 28. 선고 2022다238633).','계약',array['통지의무','상법652조','위험변경증가','고지의무와통지의무구별','대법원2022다238633'],'cycle2_supp','cycle2_supp','상법 제652조(국가법령정보센터 law.go.kr); 대법원 2024. 11. 28. 선고 2022다238633 판결(국가법령정보센터 precSeq=242125)','ai_draft','high','admin'),
('term','보험자 면책 — 고의사고(상법 제659조)','보험사고가 보험계약자·피보험자·보험수익자의 고의로 인하여 발생한 때에는 보험자는 보험금 지급 책임이 없다(상법 제659조 제1항). 다만 사망 또는 상해를 보험사고로 하는 인보험의 경우, 중대한 과실로 인한 사고에 대해서는 보험자가 면책되지 않는다(상법 제659조 제2항). 고의면책은 보험계약자 등의 고의사고를 보장하는 약관 조항은 무효로 하는 강행규정적 성격을 갖는다. 고의 여부 판단은 사고 경위·행위자의 의도 등 전반적 사정을 고려하여 판단한다.','계약',array['고의사고면책','상법659조','보험자면책사유','중대한과실면책제외인보험','면책조항'],'cycle2_supp','cycle2_supp','상법 제659조(국가법령정보센터 law.go.kr); CaseNote 상법 제659조 해설','ai_draft','medium','admin'),
('term','자살면책 2년 조항 — 예외 요건(정신질환·자유의사 결정 불능)','생명보험 약관상 피보험자 자살은 원칙적으로 면책이나, 계약 책임개시일로부터 2년 경과 후 자살은 보험금을 지급하는 예외가 있다. 또한 정신질환 등으로 자유로운 의사결정을 할 수 없는 상태에서 사망한 경우는 자살에 해당하지 않으며 보험금 지급 대상이 된다. 판례는 사망 전 직접 진단·치료 기록이 없더라도 자살자의 나이·성행·정신질환 경과·주위 상황·자살 방법 등 객관적 자료 전반을 종합하여 판단하도록 요구한다(대법원 확립 법리).','계약',array['자살면책2년','자살보험금예외','정신질환자살','자유의사결정불능','자살면책기간'],'cycle2_supp','cycle2_supp','생명보험협회 표준약관(klia.or.kr 자살면책기간 경과 후 보험자 부책 자료); 대법원 2016. 5. 12. 선고 2015다243347 판결(CaseNote); 대법원 2022. 11. 10. 선고 2022다241493 판결(CaseNote)','ai_draft','high','admin'),
('term','보장성보험 해지환급금 압류금지(민사집행법 제246조)','민사집행법 제246조 제1항 제7호는 생명·상해·질병·사고 등을 원인으로 지급받는 보장성보험의 보험금(해약환급금·만기환급금 포함) 채권을 압류금지 채권으로 규정한다. 다만 압류금지 범위는 민사집행법 시행령 제6조에서 구체화하고 있어, 사망보험금 중 1,000만원 이하 등 일정 범위만 절대적 압류금지이며 나머지는 구체적 사정에 따른다. 보장성보험 판단 기준은 만기환급금이 납입보험료 총액을 초과하지 않는 경우가 원칙이나, 보험의 주된 성격·목적도 고려한다(대법원 2007다26165).','계약',array['해지환급금압류금지','민사집행법246조','보장성보험압류불가','강제집행면제','보험금채권압류'],'cycle2_supp','cycle2_supp','민사집행법 제246조(국가법령정보센터 law.go.kr); 민사집행법 시행령 제6조(국가법령정보센터); 대법원 2009. 6. 23. 선고 2007다26165 판결(CaseNote)','ai_draft','medium','admin'),
('term','보험수익자 지정 없을 때 법정수익자 처리(상법 제733조 제2항)','보험계약자가 보험수익자를 지정하지 않은 경우 피보험자가 보험수익자가 된다. 보험계약자가 수익자 지정권을 행사하지 아니하고 사망한 경우에도 피보험자가 보험수익자가 된다(상법 제733조 제2항). 단, 피보험자가 이미 사망한 보험사고 발생 시에는 피보험자의 상속인이 보험금 청구권을 취득한다(대법원 2017다215728 법리). 수익자 변경권을 행사하지 않고 보험계약자가 사망하면 기존 수익자의 권리가 확정된다는 내용은 상법 제733조 제4항에 해당하며, 제2항과는 구분된다.','계약',array['법정수익자','상법733조2항','수익자미지정','피보험자수익자자동결정','수익자권리확정'],'cycle2_supp','cycle2_supp','상법 제733조 제2항(국가법령정보센터 law.go.kr); 대법원 2020. 2. 6. 선고 2017다215728 판결(국가법령정보센터 precSeq=210793)','ai_draft','medium','admin'),
('term','보험계약 승낙 의제(상법 제638조의2) — 30일 미통지 승낙 간주','보험자가 보험계약자로부터 보험료 상당액의 전부 또는 일부를 수령하고 청약을 받은 경우, 다른 약정이 없으면 30일 내에 낙부통지를 발송해야 하며, 이를 게을리하면 보험자가 청약을 승낙한 것으로 본다(상법 제638조의2). 인보험의 피보험자가 신체검사를 받아야 하는 경우에는 신체검사를 받은 날부터 30일을 기산한다. 이 규정은 보험계약 성립을 신속히 확정하고 보험계약자 보호를 목적으로 하며, 부활 청약의 경우에도 준용된다(상법 제650조 제3항).','계약',array['승낙의제','상법638조의2','30일미통지승낙간주','청약승낙','보험계약성립'],'cycle2_supp','cycle2_supp','상법 제638조의2(국가법령정보센터 law.go.kr); 찾기쉬운 생활법령정보 easylaw.go.kr 보험계약의 개관','ai_draft','high','admin'),
('term','보험금청구권 양도·질권 설정 가능성','보험금청구권은 양도 및 질권 설정이 가능하다. 보증보험에서 담보된 채권이 양도되면 당사자 간 별도 약정이 없는 한 보험금청구권도 수반하여 이전된다(대법원 2001. 2. 13. 선고 99다13737). 이 사건에서 대법원은 보증보험이 담보하는 채권이 양도되면 보험금청구권도 채권양수인에게 이전되며, 피보험자 변경 시 보험자 승인을 요구하는 약관은 약관규제법상 무효가 될 수 있다고 판단하였다. 한편 보험사고 발생 전 보험금청구권(정지조건부 권리)의 양도나 질권 설정이 가능한지 여부는 보험 종류 및 약관에 따라 달리 판단될 수 있으며, 보험자에게 대항하려면 보험자에 대한 통지 또는 승낙이 필요하다.','계약',array['보험금청구권양도','보험금질권설정','보증보험채권양도','보험금채권담보','보험자승낙'],'cycle2_supp','cycle2_supp','대법원 2001. 2. 13. 선고 99다13737 판결(국가법령정보센터 precSeq=147598; casenote.kr)','ai_draft','medium','admin'),
('term','보험약관 객관적·획일적 해석 원칙 — 평균적 고객 기준','보험약관은 신의성실 원칙에 따라 공정하고 합리적으로 해석하되, 개개 계약 당사자의 주관적 의도나 목적이 아닌 평균적 고객의 이해가능성을 기준으로 보험단체 전체의 이해관계를 고려하여 객관적·획일적으로 해석해야 한다(대법원 일관된 입장). 위와 같이 객관적·획일적으로 해석한 후에도 약관 조항이 다의적으로 해석되고 각 해석이 합리성을 가져 의미가 명백하지 않은 경우에 한하여 고객에게 유리하게 해석하는 작성자불이익 원칙이 적용된다. 즉 하나의 합리적 해석이 가능하면 그 해석으로 확정되고 작성자불이익 원칙은 적용되지 않는다.','계약',array['약관객관적해석','평균적고객기준','약관획일적해석','보험약관해석원칙','작성자불이익원칙'],'cycle2_supp','cycle2_supp','대법원 2018. 6. 28. 선고 2018다203395 판결(casenote.kr); 보험연구원 보험약관 해석 기준 연구(kiri.or.kr); 성균관법학 대법원 약관해석 법리 비판적 검토(slscc.skku.edu)','ai_draft','high','admin'),
('term','타인의 생명보험 사후 추인 불가 원칙','타인의 생명보험계약에서 피보험자의 서면동의가 계약 체결 시까지 없으면 계약은 확정적으로 무효이며, 계약 체결 이후 피보험자가 추인하더라도 소급하여 유효로 될 수 없다(대법원 2006. 9. 22. 선고 2004다56677). 상법 제731조는 강행규정으로 사후 치유를 허용하지 않으며, 피보험자의 동의는 각 보험계약에 대해 개별적으로 서면으로 이루어져야 하고 포괄적 동의나 묵시적·추정적 동의만으로는 부족하다. 보험자가 수년간 보험료를 수령하거나 보험금을 지급한 사실이 있더라도 무효 주장이 신의성실 원칙에 위반되지 않는다고 대법원은 판단하였다.','계약',array['타인생명보험추인불가','상법731조강행규정','서면동의사후보완불가','계약체결시동의','강행규정소급효'],'cycle2_supp','cycle2_supp','대법원 2006. 9. 22. 선고 2004다56677 판결(국가법령정보센터 precSeq=179446; casenote.kr)','ai_draft','high','admin'),
('term','고지의무의 수동적 응답의무화 논의(질문응답의무)','현행 상법은 보험계약자가 스스로 중요한 사항을 알려야 하는 자발적 고지의무를 규정하나(상법 제651조), 보험자가 서면으로 질문한 사항에 대해서만 응답하는 수동적 응답의무(질문응답의무)로 전환하자는 논의가 있다. 상법 제651조의2는 보험자가 서면으로 질문한 사항을 중요한 사항으로 추정하며 청약서가 이에 해당한다. 프랑스(1989년)·독일(2007년)은 이미 질문응답의무 방식으로 개정하였으며, 국내에서도 개정 논의가 이어지고 있다.','계약',array['질문응답의무','수동적고지의무','상법651조의2','자발적고지의무개정','서면질문사항'],'cycle2_supp','cycle2_supp','상법 제651조의2(국가법령정보센터; casenote.kr); 법률신문 보험계약 전 소비자 자발적 고지의무 수동적 응답의무로','ai_draft','high','admin'),
('term','보험계약 해지환급금 채권자 대위와 강제 해지','채권자가 채무자의 보험계약 해지환급금청구권에 대해 추심명령을 얻으면 보험계약의 해지권을 행사하여 해약환급금을 추심할 수 있다는 것이 대법원의 입장이었다(대법원 2009. 6. 23. 선고 2007다26165). 다만 민사집행법 제246조 및 동법 시행령 제6조는 생명·상해·질병 등에서 발생하는 보장성보험의 해약환급금을 압류금지채권으로 규정하여 채권자에 의한 강제 해지를 제한하고 있다. 보장성보험 여부는 원칙적으로 만기환급금이 납입보험료 총액을 초과하지 않는지를 기준으로 판단하며, 보험의 주된 성격과 목적도 종합 고려한다. 저축성보험(만기환급금이 납입보험료 초과)은 압류가 허용된다.','계약',array['해지환급금채권자대위','추심명령해지','강제해지','보장성저축성구분','압류금지예외'],'cycle2_supp','cycle2_supp','대법원 2009. 6. 23. 선고 2007다26165 판결(casenote.kr); 민사집행법 제246조·시행령 제6조(국가법령정보센터)','ai_draft','medium','admin'),
('term','보험계약 고의 위반 vs 중대한 과실 위반(고지의무 주관적 요건)','고지의무 위반이 성립하려면 보험계약자·피보험자의 고의 또는 중대한 과실이 있어야 한다(상법 제651조). 고의는 중요한 사실을 알면서 고지하지 않거나 허위로 고지하는 것이며, 중대한 과실은 현저한 부주의로 중요한 사항의 존재를 몰랐거나 중요성 판단을 잘못하여 고지하여야 할 중요한 사항임을 알지 못한 것을 의미한다. 단순한 과실이나 착오는 고지의무 위반이 아니다. 고의·중대한 과실의 입증책임은 보험자에게 있다.','계약',array['고지의무주관적요건','고의고지의무위반','중대한과실고지위반','단순과실제외','고지의무입증책임'],'cycle2_supp','cycle2_supp','상법 제651조(국가법령정보센터 law.go.kr); 보험연구원 전문자료 deve34_01.pdf(kiri.or.kr)','ai_draft','high','admin'),
('term','피보험이익 흠결과 손해보험 무효','손해보험계약에서 피보험이익(보험 목적에 대하여 경제적 이해관계)이 없으면 그 계약은 무효이다(상법 제668조). 피보험이익은 적법하고 금전으로 산정 가능한 경제적 이익이어야 하며, 도박·투기 목적의 이익은 피보험이익으로 인정되지 않는다. 피보험이익의 요건은 도박보험 방지 및 이득금지 원칙의 실현을 위해 요구된다. 생명보험은 피보험이익 요건이 손해보험처럼 엄격하게 적용되지 않으나, 타인의 생명보험에서 도박보험 방지를 위해 피보험자의 서면동의 요건이 이를 대체한다.','계약',array['피보험이익흠결무효','손해보험무효','도박보험금지','이득금지원칙','피보험이익적법성'],'cycle2_supp','cycle2_supp','상법 제668조(국가법령정보센터 law.go.kr); 보험법입문/제3장 손해보험(ko.wikibooks.org); 대법원 1998. 9. 18. 선고 96다19765 판결(casenote.kr)','ai_draft','high','admin'),
('term','소액단기전문보험업','보험업법 제2조 및 동법 시행령에 근거하여 도입된 업종으로, 소액·단기 보험만을 전문으로 취급하는 보험회사 유형. 보험기간 1년 이내, 보험금 한도 5천만원, 연간 총수입보험료 500억원 이하 요건이 적용되며, 최저자본금은 20억원으로 일반 보험회사보다 낮게 설정됨. 연금·장기요양 등 장기 보장성 및 고자본 요구 종목(원자력·자동차·화재 등)은 취급 불가. 보험업법 개정(2020. 12. 8.) 이후 보험업법 시행령 개정(2021. 5.)을 통해 세부기준이 마련되어 같은 해 6월부터 시행됨. 제도 도입 초기 신청 실적이 매우 저조하여 운영 부담 완화 필요성이 제기된 바 있다.','계약',array['소액단기전문보험업','미니보험','소액보험','단기보험','최저자본금','보험기간1년','보험금한도','보험업법'],'cycle2_supp','cycle2_supp','금융위원회 보도자료(2021) 보험업법 시행령 개정안 입법예고(소액단기전문보험업 세부기준); 국가법령정보센터 보험업법 시행령; 경향신문 2021.12.26. 소액단기전문보험업 시행 6개월 신청 0건','ai_draft','medium','admin'),
('term','임베디드 보험(Embedded Insurance)','비보험 플랫폼(커머스·모빌리티·여행·금융 등) 이용 과정에서 관련 보험이 자동·선택적으로 내장되어 별도 가입 절차 없이 또는 최소한의 절차로 보험이 제공되는 방식. 보험연구원(KIRI)은 임베디드 보험을 비금융 기업-보험사 간 직접 협력 모델, 핀테크/인슈어테크가 중개자 역할을 하는 모델, 핀테크/인슈어테크가 직접 비금융 기업 역할을 하는 모델 등 세 가지 사업 유형으로 분류한다. 국내에서는 혁신금융서비스(금융규제 샌드박스) 지정을 통해 일부 실험적 운영이 허용되고 있으며, 보험업법상 모집 관련 규제 적용 범위와 보험료 수납 방식이 핵심 규제 쟁점이다.','판매',array['임베디드보험','embedded insurance','내장형보험','플랫폼보험','인슈어테크','혁신금융서비스','샌드박스'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) 임베디드 보험 사업모형 사례(eiec.kdi.re.kr); 보험연구원 임베디드보험이란 무엇인가(kiri.or.kr/community)','ai_draft','high','admin'),
('term','온디맨드 보험(On-Demand Insurance)','피보험자가 필요한 시간·활동·장소에 한정하여 즉시 가입·해지할 수 있는 유연한 보험 방식. 특정 활동 시간 동안만 보장이 활성화되며(예: 라이딩 중에만 보장), 디지털·앱 기반으로 운영된다. 국내에서는 퍼마일(운전 시간 기반), 스포츠·레저 분야 하루 보험, 긱워커·플랫폼 종사자 대상 시간제 상해 보험 등으로 출시된 바 있다. 보험연구원(KIRI) 인슈어테크 보고서에서 온디맨드 보험 개념과 국내외 사례가 소개된다. 보험업법상 최단 보험기간 규제 및 모집 규정 적용이 주요 쟁점이다.','계약',array['온디맨드보험','시간제보험','긱워커보험','플랫폼종사자보험','인슈어테크','단기보험'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) 인슈어테크 혁명 현황 점검 및 과제(2017)(kiri.or.kr); 전자신문 인슈어테크 온디맨드보험플랫폼 활성화(etnews.com); 메트로서울 온디맨드보험 상품 출시 기사(metroseoul.co.kr)','ai_draft','medium','admin'),
('term','펫보험(반려동물보험) 보장구조','반려동물의 질병·상해로 인한 동물병원 진료비(수술비·입원비·통원비 등)를 보상하는 손해보험 상품. 금융위원회 ''반려동물보험 제도개선 방안''(2022.10.)에 따르면 자기부담금 구조, 보장 가능 진료 항목 범위, 보험료율 산정을 위한 진료비 통계 부재가 주요 과제로 지적됨. 2024년부터 일반 진료비부터 암·심장수술 등 중증질환(선택형)까지 보장 범위를 선택할 수 있는 상품 구조 개선이 추진되었으며, 핀테크 플랫폼을 통한 펫보험 비교·추천 서비스(2024.7. 잠정 출시)가 이루어짐. 반려동물 등록제·진료항목 표준화(농림부 주관)와 연계해 보험료 적정화를 추진.','보장',array['펫보험','반려동물보험','동물병원진료비','수술비','입원비','자기부담금','보험료비교공시'],'cycle2_supp','cycle2_supp','금융위원회 보도자료 — 반려동물보험 제도개선 방안(2022.10.); 금융위원회 보도자료 — 펫보험 활성화를 위한 정부-업계 협력 강화; 보험연구원 CEO Report 01호(2023.02.)','ai_draft','high','admin'),
('term','운전자보험 형사합의금(교통사고처리지원금)','자동차를 운전 중 교통사고로 타인을 상해 입혀 형사처벌 위험이 발생할 때, 피해자와의 형사합의에 소요되는 비용을 보상하는 운전자보험 특약. ''형사합의금 지원 특약'' 또는 ''교통사고처리지원금 특약''으로 불리며, 교통사고처리특례법상 처벌 특례가 적용되지 않는 중대법규위반(12대 항목) 사고 시 주로 지급 사유가 발생함. 손해배상금과 별도의 형사위로금 성격. 손보사 표준 운전자보험 약관 구조에 포함되며, 금융감독원 표준약관 목록에서 확인 가능.','보장',array['운전자보험','형사합의금','교통사고처리지원금','교통사고처리특례법','중대법규위반','형사위로금','벌금'],'cycle2_supp','cycle2_supp','법제처 찾기쉬운 생활법령정보 — 교통사고 발생시 형사처벌(easylaw.go.kr); 교통사고처리 특례법(국가법령정보센터 law.go.kr)','ai_draft','high','admin'),
('term','치아보험 대기기간(면책기간)·감액기간','치아보험에서 보장개시일로부터 일정 기간 동안 보험금을 지급하지 않거나(대기기간·면책기간), 또는 지급 보험금을 일정 비율(통상 50%)로 제한하는 기간(감액기간). 계약 전 이미 발생한 충치 등의 도덕적 해이를 방지하기 위한 제도적 장치. 임플란트·브리지·틀니 등 고가 보철치료는 일반적으로 면책기간·감액기간이 적용되며, 재해(외상)로 인한 치아 손상은 보장개시일을 계약일로 하는 경우도 있음. 상품별·담보별 세부 조건이 상이하므로 약관 확인이 필수.','보장',array['치아보험','대기기간','면책기간','감액기간','임플란트보험','틀니보험','브리지보험','보철치료'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) 보험금융연구 제33권 제3호(2022.8.) — 치아보험 손해율 관련; 법제처 찾기쉬운 생활법령정보 — 보험의 종류에 따른 보험금 지급사유 및 면책사유 예시','ai_draft','high','admin'),
('term','치아보험 보장 항목(충치·스케일링·보철)','치아보험에서 보장하는 주요 담보는 충치(우식증) 치료, 잇몸 치료(치주질환), 스케일링, 브리지·틀니·임플란트 등 보철치료, 발치, 신경치료(근관치료)로 구분됨. 비급여 항목 비중이 크고, 임플란트·틀니는 본인일부부담 건강보험 급여화(만 65세 이상)와의 중복 보상 여부가 분쟁 소지. 보철치료 특약은 별도 가입 구조가 일반적이며, 감액기간·면책기간과 함께 손해율 관리 수단으로 활용됨.','보장',array['치아보험','임플란트보험','스케일링보험','충치치료보험','보철치료특약','근관치료','치주치료'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) 보험금융연구 제33권 제3호(2022.8.) — 치아보험 손해율 관련; 보험업감독업무시행세칙(국가법령정보센터 law.go.kr)','ai_draft','high','admin'),
('term','태아보험(어린이보험 태아가입 특약)','산모가 임신 중(일반적으로 임신 8주 이후~22~24주 이전)에 태아를 피보험자로 하여 가입할 수 있는 어린이보험 또는 태아 전용 보험. 출생 후 발생 가능한 선천성 이상(질환), 출생전후기(주산기·P코드) 질환, 미숙아·저체중아 인큐베이터 비용 등을 보장. 책임개시일은 출생 시점으로 전환되며, 출생 이전 태아 상태에서의 사고는 보장되지 않는 것이 일반적. 법제처 찾기쉬운 생활법령정보(임산부 > 태아 보호하기)에 가입 절차·유의사항이 안내됨.','계약',array['태아보험','태아특약','어린이보험태아가입','선천성이상','주산기질환','저체중아','인큐베이터비용'],'cycle2_supp','cycle2_supp','법제처 찾기쉬운 생활법령정보 — 임산부 > 태아보험 가입(easylaw.go.kr); 보험연구원(KIRI) 연구보고서 — 어린이보험의 성장(2018)','ai_draft','high','admin'),
('term','주산기질환(P코드) 보장','어린이보험·태아보험에서 신생아 시기(출생전후기)에 발생하는 질환을 보장하는 담보. 한국표준질병사인분류(KCD)상 ''P코드(출생전후기에 기원한 특정병태)''에 해당하며, 신생아 뇌출혈(P52), 신생아 황달, 미숙아 합병증 등이 포함됨. 성인 뇌출혈(I코드)과 별도 코드 체계를 가지므로 약관상 명시 여부 확인이 필요. 2013년 하반기 일부 보험사가 신생아 뇌출혈(P52) 보장 구조를 변경하면서 분쟁이 발생한 사례가 있으며, 금융감독원이 진단서 병명 기준 보험금 지급을 권고함.','보장',array['주산기질환','P코드','신생아뇌출혈','출생전후기질환','어린이보험','태아보험','KCD분류'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) 연구보고서 — 어린이보험의 성장(2018); 건강보험심사평가원(HIRA) — 한국표준질병사인분류(KCD) 안내','ai_draft','high','admin'),
('term','표적항암약물치료비 특약','암 치료 방법 중 특정 분자 표적에 작용하는 표적항암제(표적치료제)를 사용한 치료 비용을 별도로 보장하는 특약. 일반 세포독성 항암제와 구분하여 별도 담보로 구성되는 경우가 있음. 요양급여 항목과 비급여 항목 모두 보장 여부가 상품별로 다르며, 건강보험 산정특례(암 산정특례)와의 연계가 중요. 보험업감독업무시행세칙 별표(표준약관 참조)에서 항암약물치료의 정의·범위를 확인할 수 있으며, 분쟁 시 KCD 코드와 약물 분류가 쟁점이 됨.','보장',array['표적항암치료비','표적항암특약','항암약물치료비','암보험특약','표적치료제','항암제비용보장'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) 연구보고서 — 암보험 약관의 해석과 관련 주요 분쟁 사례(2019); 보험업감독업무시행세칙(국가법령정보센터 law.go.kr)','ai_draft','high','admin'),
('term','세포·유전자치료제 보험 보장 이슈','CAR-T세포치료, 줄기세포치료, 유전자치료 등 첨단 바이오의약품에 해당하는 세포·유전자치료제는 고가(수억~수십억원)이면서 건강보험 급여화가 지연되는 경우가 많아, 암보험·실손보험의 비급여 보장 범위 및 보험금 지급 한도가 주요 분쟁·정책 과제로 부상. 첨단재생의료 및 첨단바이오의약품 안전 및 지원에 관한 법률에 따라 세포·유전자치료제의 법적 근거가 마련되어 있으며, 일부 보험사는 별도 첨단치료 특약을 개발·판매 중. ''세포치료제 특약''은 표준화된 약관 명칭이 없어 상품별 조건 확인 필수.','보장',array['세포치료제보험','유전자치료제보험','CAR-T보험','첨단바이오의약품','항암특약','비급여고가치료','암보험'],'cycle2_supp','cycle2_supp','첨단재생의료 및 첨단바이오의약품 안전 및 지원에 관한 법률(국가법령정보센터 law.go.kr); 보험연구원(KIRI) 연구보고서 — 암보험 약관 분쟁사례(2019)','ai_draft','medium','admin'),
('term','유병자 간편심사보험 고지항목 구조','병력이 있는 유병자도 가입 가능하도록 계약 전 알릴 의무(고지항목)를 일반 보험보다 대폭 축소·단순화한 간편심사 보험. 생명보험·장기손해보험 간편심사 상품은 업계 관행상 최근 3개월 입원·수술 여부, 최근 5년 암·뇌·심장질환 진단·치료 여부, 최근 5년 입원·수술 여부 등 3~5문항 내외 구조가 통용됨(이른바 ''3·5·5 구조''). 단, 유병력자 실손의료보험은 별도 기준(2년 이내 입원·수술, 5년 이내 암 진단 등 6항목 구조)으로 운영됨. 고지기간 단축 및 항목 축소로 역선택 위험이 높아 표준 보험 대비 보험료가 상당히 높은 것이 특징. 보험업감독규정 및 시행세칙에 간편심사 상품 요건이 규정됨.','인수',array['유병자보험','간편심사보험','고지항목축소','3문항고지','5년고지기간','유병자가입요건','간편가입'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) Monthly 제4호 — 유병자 전용 보험상품 및 가입 현황(2016.12.); 금융위원회 보도자료 — 유병력자 실손의료보험 출시(fsc.go.kr)','ai_draft','medium','admin'),
('term','간병보험 보험금 지급방식(정액형 vs 실손형)','민영 간병보험의 보험금 지급방식은 크게 정액보상형과 실손보상형으로 구분. 국내 보험회사가 취급하는 장기간병보험은 대부분 정액보상형으로, 간병 필요 상태가 인정되면 약관상 정해진 금액을 일시금 또는 연금 형태로 지급. 공적 노인장기요양보험의 등급판정(1~5등급·인지지원등급) 또는 보험회사 자체 ADL(일상생활수행능력) 기준에 따라 지급 여부 및 금액이 결정됨. 보험연구원(KIRI) 간병보험 관련 유의사항(2025.04.)에 따르면 공적 장기요양등급과 민영 간병보험 지급기준이 반드시 일치하지 않음을 유의해야 함.','보장',array['간병보험','정액형간병보험','실손형간병보험','ADL기준','장기요양등급연계','간병보험지급방식'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) 주간동향 — 간병보험 관련 유의사항(2025.04.21.); 보험연구원(KIRI) 주간동향 — 간병보험 약관 개선(2024.12.09.)','ai_draft','high','admin'),
('term','간병보험 ADL(일상생활수행능력) 지급기준','민영 간병보험에서 보험금 지급 여부를 판단하는 핵심 기준. ADL(Activities of Daily Living)은 옷 입기·세면·식사·이동·배뇨·배변 등 일상생활 기본 동작의 수행 가능 여부를 평가함. 보험약관에서 ADL 항목 중 일정 수 이상(예: 6개 중 3개 이상)을 타인의 도움 없이 수행하지 못하는 상태를 ''간병 필요 상태''로 정의하는 것이 일반적. 공적 노인장기요양보험의 장기요양인정점수(52점 이상) 기준과는 별개로 보험사 자체 기준을 사용하는 경우가 있어 민원 발생 소지가 있음.','보장',array['ADL기준','일상생활수행능력','간병보험지급기준','간병필요상태','간병보험','민영장기간병보험'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) 주간동향 — 간병보험 관련 유의사항(2025.04.21.); 보험연구원(KIRI) 주간동향 — 간병보험 약관 개선(2024.12.09.)','ai_draft','high','admin'),
('term','간병보험 약관 명확화(2024~2025 개선)','금융감독원은 2024년 11월 제7차 공정금융 추진위원회를 개최하여 간병인 사용일당 관련 보험약관 개선을 심의하고, 간병보험 약관의 모호한 표현으로 인한 분쟁 우려 해소 및 사회 안전망 강화 필요성을 확인했다. 주요 개선 과제로는 간병 필요 상태의 판정 기준(ADL 항목·판정 주체·재판정 주기), 공적 장기요양등급과 민영 기준 간 차이 안내, 보험금 지급 절차 명확화 등이 포함된다. 소비자는 가입 시 1) 민영 지급기준이 장기요양 등급과 동일한지, 2) 지급기준 충족 판정을 누가(의사·보험회사) 하는지, 3) 보험금 지급 방식(일시금·연금형)을 반드시 확인해야 한다.','민원',array['간병보험약관','간병보험개선','ADL판정주체','간병보험민원','장기요양연계','간병보험지급기준명확화'],'cycle2_supp','cycle2_supp','금융감독원 공정금융추진위원회 제7차 회의 자료(2024.11.) — 간병인 사용일당 보험약관 개선 심의; KDI 경제정보센터(eiec.kdi.re.kr) — 관련 정책자료','ai_draft','high','admin'),
('term','반려동물보험 진료비 표준화 연계','펫보험 활성화의 핵심 과제로, 동물병원별 동일 진료항목에 대한 수가 편차가 크면 합리적 보험료율 산정이 어렵다. 금융위원회·농림축산식품부 합동으로 2022년 10월 반려동물보험 제도개선 방안을 발표하여 다빈도 진료항목 표준화(100개 항목 연내 완료 목표), 진료비 게시 의무화 확대, 반려동물 등록제 개선(생체인식정보 허용, 반려묘 등록 의무화 검토) 등을 추진했다. 2024~2025년 현재 질병 3,511종·진료행위 4,930종의 코드 표준화는 완료됐으나, 진료비 자체의 표준수가제는 미도입 상태로 병원별 가격 차이는 여전히 존재한다. 진료비 표준화 없이는 도덕적 해이·역선택 문제가 지속될 수 있다.','인수',array['펫보험진료비','반려동물보험손해율','동물진료표준화','수의사수가','펫보험역선택','반려동물등록제'],'cycle2_supp','cycle2_supp','금융위원회·농림축산식품부 합동 보도자료 — 반려동물보험 제도개선 방안(2022.10.); 대한민국 정책브리핑(korea.kr) — 관련 후속 보도(2024~2025)','ai_draft','medium','admin'),
('term','금융규제 샌드박스(혁신금융서비스) — 보험 분야','금융혁신지원 특별법에 근거하여 금융위원회가 새로운 기술·서비스에 대해 기존 금융법령 규제를 한시적으로 면제·완화하는 제도. 보험 분야에서는 보험비교·추천 플랫폼, AI 기반 보험 심사, 임베디드 보험, 건강 데이터 연계 보험료 할인 등이 혁신금융서비스로 지정됐다. 2019년 제도 시행 이후 2023년까지 보험 분야 다수 건이 포함된 총 293건이 지정됐고, 이 중 169건이 시장에 출시되어 시범 운영 중이다. 지정 기간 만료 후 본인가 전환 또는 관련 법령 개정 절차를 거쳐야 정식 서비스가 가능하다.','판매',array['혁신금융서비스','금융규제샌드박스','인슈어테크','보험샌드박스','금융혁신지원특별법','보험규제특례'],'cycle2_supp','cycle2_supp','금융위원회 보도자료 — 2023년 금융규제 샌드박스 운영성과(fsc.go.kr); 한국핀테크지원센터 금융규제 샌드박스 현황(sandbox.fintech.or.kr)','ai_draft','high','admin'),
('term','지수형 보험(Index-based Insurance, 파라메트릭 보험)','실제 손해 규모 사정 없이 강수량·기온·지진 강도 등 미리 정해진 객관적 지표(인덱스·파라미터)가 약정 수준을 초과(또는 미달)하면 자동으로 보험금을 지급하는 방식. 농작물재해보험·기후리스크 보험에서 활용 사례가 확대되고 있으며, 보험연구원(KIRI)은 기후변화 자연재해 리스크 관리 맥락에서 국내 정책보험·재보험에의 활용 가능성을 분석한 보고서를 발간했다. 손해사정 절차 생략으로 신속 지급이 가능하나, 실제 손해와 지급액 간 ''기저위험(Basis Risk)'' 발생 가능성이 주요 단점이다. 국내에서는 피보험 이익 존재 및 이득 금지 원칙과의 정합성 문제가 상품화의 선결 과제로 논의되고 있다.','보장',array['지수형보험','파라메트릭보험','인덱스보험','기후보험','농작물재해보험','기저위험','자연재해보험'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) — 기후변화 자연재해 리스크관리 이슈분석 보고서(kiri.or.kr); 보험연구원 E-Conference 파라메트릭 보험의 상품화 방안','ai_draft','high','admin'),
('term','반려동물 등록제와 펫보험 연계','펫보험 가입 및 운영에서 피보험 반려동물의 동일성 확인(동물 특정)이 핵심 과제다. 금융위원회·농림축산식품부 합동 반려동물보험 제도개선 방안(2022.10.)에 따라 기존 내장형 마이크로칩 외에 생체인식정보(홍채·비문 등) 등록을 허용하고, 의무 등록 대상을 반려견에서 반려묘까지 확대하는 방안이 검토 중이다. 동물보호법(국가법령정보센터)에 근거한 등록 정보가 보험 가입 시 피보험 동물 특정 및 보험금 청구 간소화에 연계되어야 보험 인프라가 완성될 수 있다.','인수',array['반려동물등록제','펫보험인프라','동물특정','마이크로칩','반려묘보험','펫보험가입요건'],'cycle2_supp','cycle2_supp','금융위원회·농림축산식품부 합동 보도자료 — 반려동물보험 제도개선 방안(2022.10.); 동물보호법(국가법령정보센터 law.go.kr)','ai_draft','high','admin'),
('term','보험모집 제판분리(제조-판매 분리)','보험의 제조(상품 개발·인수)는 보험회사가, 판매(모집)는 GA(법인대리점) 등 독립 판매 채널이 담당하는 구조 분리. 국내 보험시장에서 GA채널 판매 비중이 지속 확대되면서 제판분리 구조가 심화되고 있다. 금융위원회는 GA에 대한 내부통제 강화·판매책임 강화 정책을 추진 중이며, ''GA 운영위험 평가제도'' 신설을 포함한 보험업감독규정 개정(2024~2025)에서 GA 관리감독 규정이 강화됐다. 보험연구원(KIRI)은 제판분리 심화에 따른 소비자보호 리스크 분석 및 모집규제 재검토 필요성을 연구 보고서로 발간했다.','판매',array['제판분리','GA판매채널','보험판매채널구조','GA내부통제','보험모집시장','GA규제강화'],'cycle2_supp','cycle2_supp','금융위원회 보도자료 — 보험판매채널 소비자 최우선 정책(fsc.go.kr, 2024~2025); 보험연구원(KIRI) — 보험모집시장 환경변화 연구보고서(nre2025-02); 보험업감독규정(국가법령정보센터)','ai_draft','high','admin'),
('term','어린이보험 성인 보장 연장','어린이보험(태아~만 15세 전후 가입 기준)의 보장기간을 만 30세·80세·100세까지 연장하는 구조. 30세 만기 상품에는 보험기간 만료 시 계약전환제도를 활용해 성인 보험으로 무심사 전환하거나 80세·100세로 연장하는 방식이 활용된다. 아이 시절 진단받은 질환이 있어도 보장 유지가 가능한 것이 최대 장점. 단, 보험기간 연장에 따른 보험료 증가, 100세 만기 시 물가·의료비 상승 대비 보험금 실질가치 감소 리스크, 무(저)해지환급형 구조의 납입기간 중 해지환급금 부재 등을 확인해야 한다. 어린이보험과 성인용 보험의 담보 중복 여부도 점검 필요.','계약',array['어린이보험성인연장','어린이보험보장기간','태아보험성인보장','장기어린이보험','어린이보험담보'],'cycle2_supp','cycle2_supp','금융감독원 파인(fine.fss.or.kr) — 보험 가입 전 주요 체크사항; 업계 공시 및 보험사 공식 상품설명서(삼성생명 등 원수사 공식 페이지)','ai_draft','medium','admin'),
('term','간편심사보험 보험료 구조(표준체 대비 할증)','유병자 간편심사보험은 고지항목 축소·대기기간 적용 등을 통해 언더라이팅 위험을 통제하지만, 역선택 위험이 높은 만큼 동일 보장 대비 표준체 보험보다 보험료가 높다. 공식 출처에서 확인되는 수준은 일반적으로 표준체 대비 약 1.5~2배 수준으로, 간편심사 실비보험의 경우 일반 실비보험 대비 1.5~2배가 통상적으로 언급된다. ''3배''까지 할증된다는 표현은 공식 출처에서 확인되지 않으므로 삭제한다. 금융감독원은 유병자(간편고지) 보험 판매 현황 전수조사를 통해 일부 보험사가 적정 요율보다 낮은 보험료를 적용하는 문제도 지적했다. 보험료가 높은 만큼 가입 전 일반 보험 가입 가능 여부를 먼저 확인하는 것이 금감원 파인(FINE)의 권고 사항이다.','인수',array['간편심사보험보험료','유병자보험보험료','표준체비교','역선택위험','간편가입보험료할증','유병자보험가입유의'],'cycle2_supp','cycle2_supp','금융감독원 파인(fine.fss.or.kr) — 보험 가입 전 주요 체크사항; 금융감독원 보도자료 — 간편고지보험 전수조사 관련(헤럴드경제 보도 근거)','ai_draft','medium','admin');
